from __future__ import annotationsimport jsonimport subprocessimport sysfrom pathlib import Pathfrom mvp_qaic_reflex_ui.common.tracker_ui_tool_manifest import (    PUBLIC_DEPLOY_BLOCK_STATUS,    manifest_ready,    ui_tracker_tool_manifest,)REPO_ROOT = Path(__file__).resolve().parents[1]def test_r1m_manifest_exposes_operator_tool_contract() -> None:    manifest = ui_tracker_tool_manifest(REPO_ROOT)    assert manifest_ready(manifest) is True    assert manifest["tool_id"] == "ui_common_tracker_kit"    assert manifest["tool_version"] == "R1M"    assert manifest["status"] == "INTERNAL_TOOL_DEPLOYED"    assert manifest["approved_visual_oracle_exists"] is True    assert manifest["public_reflex_deploy_allowed"] is False    assert manifest["public_reflex_deploy_status"] == PUBLIC_DEPLOY_BLOCK_STATUS    assert {"/dev-tracking", "/cdc-dev-tracker", "/cdc-tracker"}.issubset(set(manifest["routes"]))def test_r1m_operator_launcher_writes_json_report(tmp_path: Path) -> None:    out = tmp_path / "ui_tracker_operator_launcher.json"    result = subprocess.run(        [            sys.executable,            "tools/ui_tracker_operator_launcher.py",            "--out",            str(out),            "--repo",            str(REPO_ROOT),        ],        cwd=REPO_ROOT,        capture_output=True,        text=True,        check=False,    )    assert result.returncode == 0, result.stderr + result.stdout    assert "STATUS=MVP_R1M_UI_TRACKER_OPERATOR_LAUNCHER_READY" in result.stdout    payload = json.loads(out.read_text(encoding="utf-8"))    assert payload["ready"] is True    assert payload["status"] == "MVP_R1M_UI_TRACKER_OPERATOR_LAUNCHER_READY"    assert payload["manifest"]["tool_id"] == "ui_common_tracker_kit"